document.addEventListener("DOMContentLoaded",(function(){const e=document.getElementById("periodoi");e&&setTimeout((()=>{(async()=>{try{e.innerHTML='<option value=""></option>',e.disabled=!0;const o=document.querySelector('input[name="_csrf"]')?.value||document.querySelector('meta[name="csrf-token"]')?.content,t=await fetch("/api/periodoi",{method:"GET",headers:{"Content-Type":"application/json",...o&&{"CSRF-Token":o}},credentials:"include"});if(401===t.status)return e.innerHTML='<option value=""></option>',void(e.disabled=!0);if(!t.ok)throw new Error(`HTTP ${t.status}: ${t.statusText}`);const n=t.headers.get("content-type");if(!n||!n.includes("application/json"))throw new Error("Response is not JSON");const i=await t.text();if(!i||""===i.trim())throw new Error("Empty response from server");const r=JSON.parse(i);if(!Array.isArray(r.periodoi))throw new Error("Invalid data format");if(e.innerHTML='<option value="" selected></option>',e.disabled=!1,0===r.periodoi.length)return e.innerHTML='<option value=""></option>',void(e.disabled=!0);r.periodoi.forEach((o=>{const t=new Option(o.perigrafh,o.kodikos);e.appendChild(t)})),console.log(`Loaded ${r.periodoi.length} periods`)}catch(o){console.error("Error loading periods:",o),e.innerHTML='<option value="">Σφάλμα φόρτωσης</option>',e.disabled=!0}})()}),100)}));